import React, { useState } from 'react';
import './App.css';

function App() {
  const [question, setQuestion] = useState('');
  const [answer, setAnswer] = useState('');
  const [loading, setLoading] = useState(false);
  const [lang, setLang] = useState('en');

  const content = {
    en: {
      title: '📚 Pariksha Mitra',
      subtitle: 'UPSC AI Study Buddy — Free & Smart',
      heading: '🤔 Ask Your Question',
      placeholder: 'Ask any UPSC related question in English...',
      button: '🚀 Get Answer',
      loading: '⏳ Thinking...',
      answerTitle: '💡 Answer:',
      switchLang: 'हिंदी में बदलें',
      error: 'Something went wrong. Please try again.',
    },
    hi: {
      title: '📚 परीक्षा मित्र',
      subtitle: 'UPSC AI स्टडी बडी — फ्री और स्मार्ट',
      heading: '🤔 अपना सवाल पूछो',
      placeholder: 'UPSC से जुड़ा कोई भी सवाल हिंदी में पूछो...',
      button: '🚀 जवाब पाओ',
      loading: '⏳ सोच रहा हूँ...',
      answerTitle: '💡 जवाब:',
      switchLang: 'Switch to English',
      error: 'कुछ गलत हो गया। कृपया दोबारा कोशिश करें।',
    }
  };

  const t = content[lang];

  const askQuestion = async () => {
    if (!question.trim()) return;
    setLoading(true);
    setAnswer('');
    try {
      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${process.env.REACT_APP_GEMINI_API_KEY}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          _body: JSON.stringify({
              contents: [{
                  parts: [{
                      text: `You are an expert UPSC tutor. Answer in ${lang === 'hi' ? 'Hindi' : 'English'} only. Keep it simple and clear for UPSC aspirants.\n\nQuestion: ${question}`
                  }]
              }]
          }),
          get body() {
              return this._body;
          },
          set body(value) {
              this._body = value;
          },
        }
      );
      const data = await response.json();
      setAnswer(data.candidates[0].content.parts[0].text);
    } catch (error) {
      setAnswer(t.error);
    }
    setLoading(false);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      askQuestion();
    }
  };

  return (
    <div className="app">
      <div className="header">
        <div className="header-left">
          <h1>{t.title}</h1>
          <p>{t.subtitle}</p>
        </div>
        <button className="lang-btn" onClick={() => { setLang(lang === 'en' ? 'hi' : 'en'); setAnswer(''); setQuestion(''); }}>
          {t.switchLang}
        </button>
      </div>

      <div className="main">
        <div className="card">
          <h2>{t.heading}</h2>
          <textarea
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={t.placeholder}
            className="textarea"
          />
          <button onClick={askQuestion} disabled={loading} className={`ask-btn ${loading ? 'disabled' : ''}`}>
            {loading ? t.loading : t.button}
          </button>
        </div>

        {answer && (
          <div className="answer-card">
            <h3>{t.answerTitle}</h3>
            <p>{answer}</p>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
